// STEP 1 -- PARSE PURSUE COMMAND v2
const fs = require('fs');
const raw = $input.first().json;
const body = raw.body || raw;
const rawTitle = String(body.title || body.opportunity || body.text || '').trim();
const source = String(body.source || 'manual').toLowerCase();
const kevinNote = String(body.note || body.kevin_note || '').trim();
const entityHint = String(body.entity || '').toUpperCase();
const beachheadHint = String(body.beachhead || '').toUpperCase();
let kaiContext = {};
try { kaiContext = JSON.parse(fs.readFileSync('/data/KAI_Context.json', 'utf8')); } catch(e) {}
const resolveEntity = (title, hint) => {
  if (hint && ['FP','EAF','MONK','MULTI'].includes(hint)) return hint;
  const t = title.toLowerCase();
  if (t.includes('grant') || t.includes('workforce') || t.includes('nonprofit') || t.includes('earn') || t.includes('eaf') || t.includes('cako') || t.includes('fema preparedness') || t.includes('workforce')) return 'EAF';
  if (t.includes('sbir') || t.includes('monk') || t.includes('r&d') || t.includes('patent') || t.includes('licensing')) return 'MONK';
  if (t.includes('inspection') || t.includes('contract') || t.includes('consulting') || t.includes('bd') || t.includes('rfp') || t.includes('utility') || t.includes('bridge') || t.includes('dfr') || t.includes('police') || t.includes('medical supply')) return 'FP';
  return 'MULTI';
};
const resolveType = (title) => {
  const t = title.toLowerCase();
  if (t.includes('sbir') || t.includes('sttr')) return 'sbir';
  if (t.includes('grant') || t.includes('fema') || t.includes('earn') || t.includes('workforce')) return 'grant';
  if (t.includes('contract') || t.includes('rfp') || t.includes('inspection') || t.includes('dfr')) return 'contract';
  if (t.includes('consulting') || t.includes('advisory') || t.includes('omb m-26')) return 'consulting';
  if (t.includes('licensing') || t.includes('oem') || t.includes('partnership')) return 'licensing';
  if (t.includes('job') || t.includes('employment') || t.includes('ojt') || t.includes('position') || t.includes('hire')) return 'employment';
  return 'contract';
};
const entity = resolveEntity(rawTitle, entityHint);
const opportunityType = resolveType(rawTitle);
const triggerJordan = true;
const triggerIris = entity === 'EAF' || entity === 'MULTI';
const triggerAtlas = entity === 'MONK';
return [{ json: {
  title: rawTitle,
  source,
  kevinNote,
  entity,
  beachheadHint,
  opportunityType,
  triggerJordan,
  triggerIris,
  triggerAtlas,
  timestamp: new Date().toISOString(),
  founderName: (kaiContext.founder || {}).name || 'Kevin Alexander Smith',
  founderCredentials: ((kaiContext.founder || {}).credentials || []).join(', ')
}}];

// STEP 2 -- UPSERT TO PIPELINE (v2 -- prevents duplicates)
// Uses Supabase upsert with on_conflict=title,entity
// If same title+entity already exists, updates status to pursuing
const https = require('https');
const input = $input.first().json;
const SUPABASE_URL = ($env.SUPABASE_URL || '').replace('https://','').replace('http://','');
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY || '';
const record = {
  title: input.title,
  source: input.source,
  entity: input.entity,
  opportunity_type: input.opportunityType,
  beachhead: input.beachheadHint || null,
  status: 'pursuing',
  kevin_note: input.kevinNote || null,
  jordan_triggered: input.triggerJordan,
  iris_triggered: input.triggerIris,
  atlas_triggered: input.triggerAtlas,
  discovered_by_agent: 'Nova-Pursue v2',
  run_date: new Date().toISOString().slice(0,10)
};
let pipelineId = null;
let writeStatus = 'failed';
if (!SUPABASE_URL || !SUPABASE_KEY) {
  writeStatus = 'skipped -- missing Supabase credentials';
  return [{ json: { ...input, pipelineId, writeStatus } }];
}
try {
  const body = JSON.stringify(record);
  const result = await new Promise((resolve, reject) => {
    const req = https.request({
      hostname: SUPABASE_URL,
      port: 443,
      // Upsert: if title+entity conflict exists, update instead of insert
      path: '/rest/v1/pipeline',
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'apikey': SUPABASE_KEY,
        'Authorization': 'Bearer ' + SUPABASE_KEY,
        // merge-duplicates = upsert on any unique constraint (title+entity if defined)
        'Prefer': 'resolution=merge-duplicates,return=representation',
        'Content-Length': Buffer.byteLength(body)
      }
    }, (res) => { let d = ''; res.on('data', c => d += c); res.on('end', () => resolve({ status: res.statusCode, body: d })); });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
  if (result.status === 201 || result.status === 200) {
    writeStatus = 'saved';
    try { pipelineId = JSON.parse(result.body)[0]?.id || null; } catch(e) {}
  } else {
    writeStatus = 'error_' + result.status + ': ' + result.body.substring(0, 200);
  }
} catch(e) {
  writeStatus = 'error: ' + e.message;
}
return [{ json: { ...input, pipelineId, writeStatus } }];

